mapper.select:
SELECT content 
FROM Comment 
WHERE comment_no = #{targetId}

mapper.update:
UPDATE Comment 
SET is_deleted = 1 
WHERE comment_no = #{commentNo}
	OR parent_no = #{commentNo}

UPDATE comment 
SET content = #{content}
WHERE comment_no = #{commentNo} 
  AND user_id = #{userId}

mapper.select:
SELECT COUNT(*) 
FROM comment_like 
WHERE comment_no = #{commentNo} 
  AND user_id = #{userId}

mapper.update:
UPDATE comment 
SET like_cnt = like_cnt + #{count} 
WHERE comment_no = #{commentNo}
